import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Conway's Game of Life", () => {
  it.todo("should return no living cells when given no living cells");
  it.todo("should kill a single living cell with no neighbors (underpopulation)");
  it.todo("should kill a living cell with only one living neighbor (underpopulation)");
  it.todo("should keep a living cell alive with two living neighbors");
  it.todo("should keep a living cell alive with three living neighbors");
  it.todo("should kill a living cell with more than three living neighbors (overpopulation)");
  it.todo("should bring a dead cell to life with exactly three living neighbors (reproduction)");
  it.todo("should handle living cells at negative coordinates");
});
